`lookup` est optimisé pour enrichir depuis une petite table de référence :

```kql
// Table de référence : IPs malveillantes connues
let ThreatIntel = datatable(MaliciousIP:string, ThreatType:string)
[
    "185.234.219.1", "C2 Server",
    "45.33.32.156",  "Scanner",
    "192.241.220.125", "Exploit Kit"
];

// Enrichir les connexions avec la Threat Intel
SigninLogs
| where TimeGenerated > ago(24h)
| lookup kind=leftouter ThreatIntel on $left.IPAddress == $right.MaliciousIP
| where isnotempty(ThreatType)  // Garder seulement les matchs
| project TimeGenerated, UserPrincipalName, IPAddress, ThreatType

// lookup vs join :
// lookup est plus rapide quand la table droite est petite
// join est plus général (supports tous les kinds)
```

```kql
// Variables avec let pour des sous-requêtes réutilisables
let FailedLogins =
    SecurityEvent
    | where TimeGenerated > ago(1h)
    | where EventID == 4625
    | summarize FailCount=count() by AttackerIP=IpAddress;

let SuccessfulLogins =
    SecurityEvent
    | where TimeGenerated > ago(1h)
    | where EventID == 4624
    | summarize SuccessCount=count() by VictimIP=IpAddress;

// Corréler : IPs avec beaucoup d'échecs suivis d'un succès
// (signe d'un brute force réussi)
FailedLogins
| join kind=inner SuccessfulLogins
    on $left.AttackerIP == $right.VictimIP
| where FailCount > 10 and SuccessCount >= 1
| project IP=AttackerIP, FailCount, SuccessCount
| sort by FailCount desc
```

